#!/usr/bin/env python3
"""
OSRS SOULS v4 — Complete Standalone Single-File Game
DS2 Remastered Majula Graphics + OSRS Mechanics + Xbox Gamepad
Run: python SS.py
"""
import http.server, threading, webbrowser, io, socket, struct, hashlib, base64, json
import os, sys, time, subprocess, shutil, datetime, atexit

# ============================================================================
# === ANALYSIS TERMINAL (hard-coded, runs every session) =====================
# ============================================================================
# A dedicated terminal that surfaces 100% of runtime errors during a session:
# - Every uncaught JS error in the browser (window.onerror)
# - Every unhandled promise rejection
# - Every console.error / console.warn
# - Every click on a button / inline-onclick element (breadcrumb for context)
# - Every server-side exception (do_GET/do_POST try-blocks)
# The browser POSTs to /log; the server appends to LOG_PATH and prints to stdout.
# A separate OS terminal window is spawned on startup that `tail -F`s the log,
# giving the developer a live, isolated view of *only* the errors stream.
# Doctrine: E12 (fail-loud) + R26 (Error Ledger) + new R30 (Live Analysis Terminal).
# ============================================================================
LOG_DIR = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'logs')
os.makedirs(LOG_DIR, exist_ok=True)
LOG_PATH = os.path.join(LOG_DIR, 'soulscape_errors.log')
_log_lock = threading.Lock()

def _now_iso():
    return datetime.datetime.now().strftime('%Y-%m-%d %H:%M:%S.%f')[:-3]

def log_event(kind, payload):
    """Thread-safe append to LOG_PATH + echo to stdout.
    kind: short tag, e.g. 'JS_ERROR', 'JS_REJECT', 'CONSOLE', 'CLICK', 'SRV_ERROR'.
    payload: dict or string. Dicts are json-encoded.
    """
    try:
        if isinstance(payload, dict):
            try:
                body = json.dumps(payload, ensure_ascii=False, default=str)
            except Exception:
                body = repr(payload)
        else:
            body = str(payload)
        line = f'[{_now_iso()}] [{kind}] {body}\n'
        with _log_lock:
            with open(LOG_PATH, 'a', encoding='utf-8') as f:
                f.write(line)
            sys.stdout.write(line)
            sys.stdout.flush()
    except Exception as _e:
        # Never let logging itself crash the server
        try: sys.stderr.write(f'[log_event failure] {_e}\n')
        except Exception: pass

def _truncate_log_and_banner():
    try:
        with open(LOG_PATH, 'w', encoding='utf-8') as f:
            f.write('=' * 78 + '\n')
            f.write(f'  SOULSCAPE ANALYSIS TERMINAL — session started {_now_iso()}\n')
            f.write(f'  Log file: {LOG_PATH}\n')
            f.write('  Every JS error, promise rejection, console.error/warn, and click on a\n')
            f.write('  button/inline-onclick element is streamed here in real-time.\n')
            f.write('=' * 78 + '\n')
    except Exception as e:
        sys.stderr.write(f'[analysis-terminal] could not initialise log: {e}\n')

def spawn_analysis_terminal():
    """Spawn a separate OS terminal window that live-tails LOG_PATH.
    Tries common Linux emulators in priority order; falls back to in-process
    tail-thread (prints to the main terminal with prefix) if none found.
    """
    _truncate_log_and_banner()
    tail_cmd = f"tail -n +1 -F '{LOG_PATH}'"
    title = 'SoulScape — Analysis Terminal'
    # (binary, argv-template) — argv uses {tail} and {title} placeholders
    candidates = [
        ('gnome-terminal',  ['gnome-terminal', '--title', title, '--', 'bash', '-c', f'{tail_cmd}; exec bash']),
        ('konsole',         ['konsole', '--title', title, '-e', 'bash', '-c', f'{tail_cmd}; exec bash']),
        ('xfce4-terminal',  ['xfce4-terminal', f'--title={title}', '-e', f'bash -c "{tail_cmd}; exec bash"']),
        ('mate-terminal',   ['mate-terminal', '--title', title, '--', 'bash', '-c', f'{tail_cmd}; exec bash']),
        ('terminator',      ['terminator', '-T', title, '-e', f'bash -c "{tail_cmd}; exec bash"']),
        ('tilix',           ['tilix', '--title', title, '-e', f'bash -c "{tail_cmd}; exec bash"']),
        ('alacritty',       ['alacritty', '--title', title, '-e', 'bash', '-c', f'{tail_cmd}; exec bash']),
        ('kitty',           ['kitty', '--title', title, 'bash', '-c', f'{tail_cmd}; exec bash']),
        ('xterm',           ['xterm', '-T', title, '-e', f'bash -c "{tail_cmd}; exec bash"']),
    ]
    if sys.platform.startswith('win'):
        # Windows fallback (PowerShell window)
        try:
            subprocess.Popen(['cmd', '/c', 'start', '"' + title + '"', 'powershell', '-NoExit', '-Command',
                              f"Get-Content -Path '{LOG_PATH}' -Wait"], shell=False)
            print(f'[analysis-terminal] Spawned PowerShell window tailing {LOG_PATH}')
            return
        except Exception as e:
            sys.stderr.write(f'[analysis-terminal] PowerShell spawn failed: {e}\n')
    elif sys.platform == 'darwin':
        try:
            applescript = f'tell application "Terminal" to do script "tail -n +1 -F \'{LOG_PATH}\'"'
            subprocess.Popen(['osascript', '-e', applescript])
            print(f'[analysis-terminal] Spawned Terminal.app tailing {LOG_PATH}')
            return
        except Exception as e:
            sys.stderr.write(f'[analysis-terminal] Terminal.app spawn failed: {e}\n')
    else:
        for binary, argv in candidates:
            if shutil.which(binary):
                try:
                    subprocess.Popen(argv, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL,
                                     start_new_session=True)
                    print(f'[analysis-terminal] Spawned {binary} tailing {LOG_PATH}')
                    return
                except Exception as e:
                    sys.stderr.write(f'[analysis-terminal] {binary} spawn failed: {e}\n')
                    continue
    # === Fallback: in-process tail thread that mirrors log lines to stderr with prefix ===
    sys.stderr.write('[analysis-terminal] No GUI terminal emulator found — '
                     'falling back to in-process tail (errors will appear in this terminal '
                     'prefixed with [ANALYSIS]).\n')
    def _inproc_tail():
        try:
            with open(LOG_PATH, 'r', encoding='utf-8') as f:
                f.seek(0, 2)  # end of file
                while True:
                    line = f.readline()
                    if not line:
                        time.sleep(0.25)
                        continue
                    sys.stderr.write('[ANALYSIS] ' + line)
                    sys.stderr.flush()
        except Exception as e:
            sys.stderr.write(f'[analysis-terminal] in-process tail died: {e}\n')
    threading.Thread(target=_inproc_tail, daemon=True).start()

