  { id: 'orgrakk_warband', displayName: 'Orgrakk Warband', description: 'Orc-blooded raiders of the western canyons. Honour-by-combat; rep is earned with blood, not bribes.', baseStanding: 0, opposing: ['stormhaven_watch'], tiers: STANDARD_TIERS },
  { id: 'pokehaven_trainers', displayName: 'PokéHaven Trainers\' Guild', description: 'Tamers who breed, train, and broker captured creatures. Cosmetic rosettes and rare incubators at high tiers.', baseStanding: 0, opposing: [], tiers: STANDARD_TIERS },
