SpellRegistry.register(_spell({ id: 'spell.fire.bolt', name: 'Fire Bolt', school: 'fire', book: 'standard', level: 15, cost: { mp: 10 }, cast: 0.7, range: 28, shape: 'line', damage: { fire: 38 }, vfx: { cast: 'fire_charge', travel: 'fire_bolt_streak', impact: 'fire_bloom_small' }, anim: 'cast_1h', sfx: ['cast_fire_mid', 'impact_fire_mid'], desc: 'A tight, fast-moving fireball with a corkscrew tail of black smoke; on hit it cracks like dry wood.' }));
SpellRegistry.register(_spell({ id: 'spell.fire.blast', name: 'Fire Blast', school: 'fire', book: 'standard', level: 30, cost: { mp: 18 }, cast: 0.9, range: 14, shape: 'cone', damage: { fire: 70 }, vfx: { cast: 'fire_charge_big', travel: 'fire_cone', impact: 'fire_bloom_mid' }, anim: 'cast_2h', sfx: ['cast_fire_hi', 'impact_fire_hi'], desc: 'A 30 degree gout of roaring flame washes forward from the caster\'s palm, painting a wedge of charred ground.' }));
SpellRegistry.register(_spell({ id: 'spell.fire.wave', name: 'Fire Wave', school: 'fire', book: 'standard', level: 45, cost: { mp: 28 }, cast: 1.0, range: 12, shape: 'aoe', damage: { fire: 95 }, vfx: { cast: 'fire_pulse', travel: 'fire_ring', impact: 'fire_bloom_ring' }, anim: 'cast_2h', sfx: ['cast_fire_hi', 'impact_fire_wave'], desc: 'An expanding ring of waist-high orange flame races outward from the caster, leaving black scorch lines.' }));
