            { id: 'r2_drowned_hall',    name: 'Drowned Hall',        shape: 'corridor', dimensions: { w: 18,  h: 80,  d: 1 }, ceiling: 10, theme: 'submerged_pillars', adds: [{ id: 'deep_one_thrall', count: 6 }, { id: 'kelp_horror', count: 1 }], encounterBudget: 240 },
