      '.ss24-btn:hover{background:#2a3252;}',
      '#ss24-subtitle{position:fixed;top:7%;left:50%;transform:translate(-50%,-12px);max-width:70vw;min-width:280px;padding:10px 18px;background:rgba(0,0,0,0.72);color:#fff;border-radius:8px;font-family:system-ui,sans-serif;font-size:15px;text-align:center;text-shadow:0 1px 3px #000;pointer-events:none;opacity:0;transition:opacity .35s ease, transform .35s ease;z-index:9998;border-left:3px solid var(--ss-accent,#ffc857);}',
      '#ss24-subtitle.show{opacity:1;transform:translate(-50%,0);}',
