    { id:'ember_owl',           name:'Ember Owl',           type:'flying', speedMult:1.40, cooldownS:16, durabilityMax:220, baseHP:460, color:'#cc5a1a', colorAccent:'#ffd07a', specialAbility:{ id:'silent_dive', name:'Silent Dive', cooldownS:14, durationS:1.6, effect:{ dmgMult:2.2, crit:true } }, lore:'A pyre with feathers; hunters say it learns names before it learns flight.' },
