# === RAW WEBSOCKET SERVER (no pip install needed) ===
WS_MAGIC = b'258EAFA5-E914-47DA-95CA-5AB5DC65FE97'
ws_clients = {}  # id -> socket
ws_lock = threading.Lock()
_next_id = [0]

def ws_handshake(conn):
    data = conn.recv(4096)
    key = None
    for line in data.decode(errors='ignore').split('\r\n'):
        if line.lower().startswith('sec-websocket-key:'):
            key = line.split(':', 1)[1].strip()
    if not key:
        return False
    accept = base64.b64encode(hashlib.sha1(key.encode() + WS_MAGIC).digest()).decode()
    conn.sendall((
        'HTTP/1.1 101 Switching Protocols\r\n'
        'Upgrade: websocket\r\n'
        'Connection: Upgrade\r\n'
        f'Sec-WebSocket-Accept: {accept}\r\n\r\n'
    ).encode())
    return True

def ws_decode(data):
    if len(data) < 2: return None, data
    b1, b2 = data[0], data[1]
    op = b1 & 0x0F
    masked = b2 & 0x80
    ln = b2 & 0x7F
    off = 2
    if ln == 126:
        if len(data) < 4: return None, data
        ln = struct.unpack('>H', data[2:4])[0]; off = 4
    elif ln == 127:
        if len(data) < 10: return None, data
        ln = struct.unpack('>Q', data[2:10])[0]; off = 10
    if masked:
        if len(data) < off + 4: return None, data
        mask = data[off:off+4]; off += 4
    if len(data) < off + ln: return None, data
    payload = data[off:off+ln]
    if masked: payload = bytes(b ^ mask[i % 4] for i, b in enumerate(payload))
    remain = data[off+ln:]
    if op == 8: return ('close', b''), remain
    if op == 9: return ('ping', payload), remain
    return ('text', payload.decode()), remain

def ws_encode(text):
    d = text.encode()
    f = bytearray([0x81])
    if len(d) < 126: f.append(len(d))
    elif len(d) < 65536: f.append(126); f.extend(struct.pack('>H', len(d)))
    else: f.append(127); f.extend(struct.pack('>Q', len(d)))
    f.extend(d)
    return bytes(f)

def ws_broadcast(msg, exclude=None):
    frame = ws_encode(msg)
    with ws_lock:
        for cid, c in list(ws_clients.items()):
            if cid != exclude:
                try: c.sendall(frame)
                except: pass

def ws_client(conn, addr):
    if not ws_handshake(conn):
        conn.close(); return
    cid = _next_id[0]; _next_id[0] += 1
    with ws_lock: ws_clients[cid] = conn
    try:
        conn.sendall(ws_encode(json.dumps({'t': 'id', 'id': cid})))
        buf = b''
        while True:
            chunk = conn.recv(4096)
            if not chunk: break
            buf += chunk
            while buf:
                result, buf = ws_decode(buf)
                if result is None: break
                kind, payload = result
                if kind == 'close': raise ConnectionError
                if kind == 'ping':
                    conn.sendall(bytes([0x8A, len(payload)]) + payload)
                if kind == 'text':
                    try:
                        d = json.loads(payload)
                        d['id'] = cid  # enforce server-side ID
                        ws_broadcast(json.dumps(d), exclude=cid)
                    except: pass
    except: pass
    finally:
        with ws_lock: ws_clients.pop(cid, None)
        try: ws_broadcast(json.dumps({'t': 'l', 'id': cid}))
        except: pass
        conn.close()

def ws_server():
    srv = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    srv.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
    srv.bind(('0.0.0.0', 8081))
    srv.listen(20)
    while True:
        c, a = srv.accept()
        threading.Thread(target=ws_client, args=(c, a), daemon=True).start()

# === HTTP SERVER ===
class GameHandler(http.server.BaseHTTPRequestHandler):
    def do_GET(self):
        try:
            if self.path in ('/', '/index.html', '/SS.html', '/game'):
                data = GAME_HTML.encode('utf-8')
                self.send_response(200)
                self.send_header('Content-Type', 'text/html; charset=utf-8')
                self.send_header('Content-Length', str(len(data)))
                self.send_header('Cache-Control', 'no-cache, no-store, must-revalidate, max-age=0')
                self.send_header('Pragma', 'no-cache')
                self.send_header('Expires', '0')
                self.send_header('ETag', '"v' + str(hash(GAME_HTML) & 0xFFFFFFFF) + '"')
                self.end_headers()
                self.wfile.write(data)
            elif self.path == '/log/health':
                # Sanity ping for the browser-side reporter
                self.send_response(200)
                self.send_header('Content-Type', 'text/plain')
                self.end_headers()
                self.wfile.write(b'ok')
            else:
                self.send_error(404)
        except Exception as e:
            log_event('SRV_ERROR', {'where': 'do_GET', 'path': self.path, 'err': repr(e)})
            raise
    def do_POST(self):
        # === Analysis Terminal ingest endpoint =====================================
        # Accepts JSON from the browser; appends to LOG_PATH (which is tailed by
        # the dedicated analysis terminal window). Hard-coded — runs every session.
        try:
            if self.path == '/log':
                length = int(self.headers.get('Content-Length', '0') or 0)
                length = max(0, min(length, 64 * 1024))  # cap at 64 KB per event
                raw = self.rfile.read(length) if length else b''
                try:
                    payload = json.loads(raw.decode('utf-8', 'replace')) if raw else {}
                except Exception:
                    payload = {'raw': raw[:2048].decode('utf-8', 'replace')}
                if not isinstance(payload, dict):
                    payload = {'value': payload}
                kind = str(payload.pop('kind', 'CLIENT'))[:32]
                # Attach the client's IP as a low-noise tag
                try: payload.setdefault('peer', self.client_address[0])
                except Exception: pass
                log_event(kind, payload)
                self.send_response(204)
                self.send_header('Access-Control-Allow-Origin', '*')
                self.end_headers()
            else:
                self.send_error(404)
        except Exception as e:
            log_event('SRV_ERROR', {'where': 'do_POST', 'path': self.path, 'err': repr(e)})
            try: self.send_error(500)
            except Exception: pass
    def log_message(self, fmt, *args):
        pass

